import React, { useState, useRef, useEffect } from 'react';
import { Bot, User, Send, Sparkles, MessageSquare, RefreshCcw } from 'lucide-react';
import './AIAssistantPage.css';

const FEATURES = [
  { icon: '✍️', title: 'Professional Rephrasing', desc: 'Paste any sentence and get a polished, resume-ready version' },
  { icon: '💡', title: 'Skill Suggestions', desc: 'Get role-specific skill recommendations to boost your profile' },
  { icon: '📊', title: 'ATS Optimization Tips', desc: 'Learn how to make your resume more ATS-friendly' },
  { icon: '📝', title: 'Summary Writing', desc: 'Get help crafting a compelling professional summary' },
  { icon: '🎯', title: 'Action Verbs', desc: 'Discover powerful action verbs to start your bullet points' },
  { icon: '🔄', title: 'Content Improvement', desc: 'Improve any section of your resume with AI guidance' },
];

const QUICK_PROMPTS = [
  { label: 'Rephrase a sentence', prompt: 'Make this professional: "I worked on building a website for customers"' },
  { label: 'Skills for SWE', prompt: 'What skills should I have as a Software Engineer?' },
  { label: 'ATS tips', prompt: 'Give me tips to improve my ATS score' },
  { label: 'Write summary', prompt: 'Help me write a professional summary for a Full Stack Developer with 3 years experience' },
  { label: 'Action verbs', prompt: 'Give me powerful action verbs for a tech resume' },
  { label: 'Improve bullet', prompt: 'Make this sound better: "was responsible for testing and fixing bugs in the codebase"' },
];

const getAIResponse = (msg) => {
  const lower = msg.toLowerCase();
  if (lower.includes('summary') || lower.includes('full stack') || lower.includes('write a')) {
    return `Here's a strong professional summary template:\n\n**Full Stack Developer | 3 Years Experience**\n\n*"Results-driven Full Stack Developer with 3 years of experience building scalable web applications using React and Node.js. Delivered high-impact solutions serving 50,000+ daily active users with 99.9% uptime. Proficient in TypeScript, PostgreSQL, and AWS. Passionate about clean architecture, performance optimization, and collaborative agile development."*\n\n**Key elements of a great summary:**\n• Start with your title and years of experience\n• Include a key metric or achievement\n• Mention your top 3-4 technologies\n• End with what you bring to the team\n\nWant me to customize this for a different role?`;
  }
  if (lower.includes('skill') && (lower.includes('swe') || lower.includes('software engineer') || lower.includes('what skill'))) {
    return `**Essential Skills for Software Engineers in 2024:**\n\n🔧 **Core Technical:**\nPython, Java/JavaScript/TypeScript, Data Structures & Algorithms, System Design, REST APIs, Git\n\n🌐 **Web Development:**\nReact or similar frameworks, Node.js, SQL/NoSQL databases, Docker\n\n☁️ **Cloud & DevOps:**\nAWS/GCP/Azure, CI/CD pipelines, Linux basics\n\n🤝 **Professional:**\nAgile/Scrum, Code review practices, Technical documentation\n\n💎 **Bonus (stands out):**\nKubernetes, Microservices, ML/AI basics, GraphQL\n\nAim to have 8-12 relevant skills on your resume. Quality over quantity!`;
  }
  if (lower.includes('ats') || lower.includes('applicant tracking')) {
    return `**Top ATS Optimization Tips:**\n\n1️⃣ **Use keywords from the job description** — ATS systems scan for exact matches\n\n2️⃣ **Standard section headers** — Use "Work Experience", "Education", "Skills" (not creative names)\n\n3️⃣ **Avoid tables and columns** — They confuse ATS parsers; use single-column layouts\n\n4️⃣ **Include both formats** — Write "ML" and "Machine Learning", "JS" and "JavaScript"\n\n5️⃣ **Quantify achievements** — "Increased performance by 40%" beats "improved performance"\n\n6️⃣ **Use .docx or .pdf** — These formats parse best\n\n7️⃣ **No images or graphics** — ATS can't read them\n\n8️⃣ **Consistent date format** — Use "Jan 2022 – Present" throughout\n\n📊 Use SkillFolio's ATS Score tool to check your specific score!`;
  }
  if (lower.includes('action verb') || lower.includes('bullet') || lower.includes('powerful verb')) {
    return `**Power Action Verbs for Tech Resumes:**\n\n🚀 **Development & Engineering:**\nBuilt, Developed, Engineered, Architected, Designed, Implemented, Deployed, Integrated, Optimized, Refactored\n\n📈 **Leadership & Initiative:**\nLed, Spearheaded, Championed, Directed, Mentored, Guided, Established, Founded, Launched\n\n⚡ **Achievement & Impact:**\nDelivered, Achieved, Exceeded, Reduced, Increased, Improved, Accelerated, Streamlined, Saved, Generated\n\n🔧 **Collaboration:**\nCollaborated, Partnered, Coordinated, Facilitated, Supported, Contributed, Worked with, Aligned\n\n📊 **Analysis & Problem Solving:**\nAnalyzed, Diagnosed, Identified, Researched, Investigated, Evaluated, Assessed, Resolved\n\n**Pro tip:** Always use past tense and start every bullet point with a strong action verb!`;
  }
  if (lower.includes('make') || lower.includes('rephrase') || lower.includes('professional') || lower.includes('better') || lower.includes('improve') || lower.includes('responsible')) {
    const cleaned = msg.replace(/^(make this professional|rephrase|improve|make this sound better):?\s*/i, '').trim();
    return `Here's a more professional version:\n\n**Original:** "${cleaned}"\n\n**Improved:** *"Engineered and maintained robust web solutions, collaborating cross-functionally to deliver high-quality features that enhanced user experience and system reliability."*\n\n**Why this works:**\n• Starts with a strong action verb (Engineered)\n• Removes passive language ("was responsible for")\n• Adds impact-focused language\n• Sounds more professional and confident\n\n**More options:**\n• *"Developed and optimized core features, reducing bug count by 35% through rigorous testing and systematic debugging"*\n• *"Collaborated with cross-functional teams to identify, troubleshoot, and resolve critical software defects"*\n\nWant me to try a different approach?`;
  }
  return `I'm your SkillFolio AI Assistant! Here's what I can help with:\n\n✍️ **Professional rephrasing** – paste any text and I'll make it resume-ready\n💡 **Skill recommendations** – for any tech role\n📊 **ATS optimization** – tips to pass automated screening\n📝 **Summary writing** – craft a compelling professional bio\n🎯 **Action verbs** – powerful words to start bullet points\n🔍 **Content review** – improve any resume section\n\nJust ask me anything, or use the quick prompts below!`;
};

const AIAssistantPage = () => {
  const [messages, setMessages] = useState([{
    id: 1, role: 'bot',
    text: "Hi! I'm your SkillFolio AI Assistant 🤖\n\nI can help you craft a professional resume by:\n• Rephrasing sentences into polished language\n• Recommending skills for your target role\n• Giving ATS optimization advice\n• Writing or improving any resume section\n\nWhat would you like help with today?",
  }]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const endRef = useRef(null);

  useEffect(() => { endRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [messages]);

  const sendMessage = (text) => {
    const msg = text || input;
    if (!msg.trim()) return;
    setInput('');
    setMessages(prev => [...prev, { id: Date.now(), role: 'user', text: msg }]);
    setIsTyping(true);
    setTimeout(() => {
      setMessages(prev => [...prev, { id: Date.now() + 1, role: 'bot', text: getAIResponse(msg) }]);
      setIsTyping(false);
    }, 1000);
  };

  const clearChat = () => setMessages([{ id: 1, role: 'bot', text: "Chat cleared! How can I help you today?" }]);

  const formatText = (text) => text.split('\n').map((line, i) => {
    line = line.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>').replace(/\*(.+?)\*/g, '<em>$1</em>');
    return <p key={i} dangerouslySetInnerHTML={{ __html: line || '&nbsp;' }} />;
  });

  return (
    <div className="ai-page">
      <div className="container">
        <div className="ai-header">
          <p className="section-eyebrow"><Sparkles size={13} /> AI Assistant</p>
          <h1 className="ai-title">SkillFolio AI Assistant</h1>
          <p className="ai-subtitle">Your intelligent writing partner for building a standout resume</p>
        </div>

        <div className="ai-layout">
          {/* Left: features */}
          <aside className="ai-features-panel">
            <h3 className="features-panel-title">What I can do</h3>
            <div className="features-list">
              {FEATURES.map((f, i) => (
                <div key={i} className="ai-feature-item">
                  <span className="feature-emoji">{f.icon}</span>
                  <div>
                    <div className="feature-name">{f.title}</div>
                    <div className="feature-desc">{f.desc}</div>
                  </div>
                </div>
              ))}
            </div>
          </aside>

          {/* Right: chat */}
          <div className="ai-chat-panel">
            <div className="ai-chat-header">
              <div className="ai-chat-header-left">
                <div className="ai-avatar"><Bot size={20} /></div>
                <div>
                  <div className="ai-chat-name">SkillFolio AI</div>
                  <div className="ai-online"><span className="online-dot" /> Online</div>
                </div>
              </div>
              <button className="clear-btn" onClick={clearChat}><RefreshCcw size={15} /> Clear Chat</button>
            </div>

            <div className="ai-messages">
              {messages.map(msg => (
                <div key={msg.id} className={`ai-msg ${msg.role}`}>
                  <div className="ai-msg-avatar">
                    {msg.role === 'bot' ? <Bot size={15} /> : <User size={15} />}
                  </div>
                  <div className="ai-msg-bubble">
                    {formatText(msg.text)}
                  </div>
                </div>
              ))}
              {isTyping && (
                <div className="ai-msg bot">
                  <div className="ai-msg-avatar"><Bot size={15} /></div>
                  <div className="ai-msg-bubble typing-bubble">
                    <span /><span /><span />
                  </div>
                </div>
              )}
              <div ref={endRef} />
            </div>

            <div className="ai-quick-prompts">
              <p className="qp-label"><MessageSquare size={12} /> Try a prompt:</p>
              <div className="qp-list">
                {QUICK_PROMPTS.map((p, i) => (
                  <button key={i} className="qp-btn" onClick={() => sendMessage(p.prompt)}>
                    {p.label}
                  </button>
                ))}
              </div>
            </div>

            <div className="ai-input-row">
              <input
                type="text"
                className="ai-input"
                placeholder="Ask anything — paste text to improve, ask for skills, get resume tips..."
                value={input}
                onChange={e => setInput(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && sendMessage()}
              />
              <button className="ai-send-btn" onClick={() => sendMessage()} disabled={!input.trim()}>
                <Send size={17} />
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AIAssistantPage;
